require.config({"config": {
        "text":{"Magento_PaymentServicesPaypal/template/payment/vault.html":"<!--\n/**\n * Copyright \u00a9 Magento, Inc. All rights reserved.\n * See COPYING.txt for license details.\n */\n-->\n<div class=\"payment-method\" css=\"'_active': (getId() == isChecked())\" id=\"payment-method-payment_services_paypal_vault\">\n    <div class=\"payment-method-title field choice\">\n        <input type=\"radio\"\n               name=\"payment[method]\"\n               class=\"radio\"\n               data-bind=\"attr: {'id': getId()}, value: getId(), checked: isChecked, click: selectPaymentMethod, visible: isRadioButtonVisible()\">\n        <label class=\"label\" attr=\"'for': getId()\">\n            <img attr=\"{\n                'src': getIcons(getCardBrand()).url,\n                'width': getIcons(getCardBrand()).width,\n                'height': getIcons(getCardBrand()).height,\n                'alt': getIcons(getCardBrand()).title\n            }\" class=\"payment-icon\">\n            <span style=\"font-weight:bold\" text=\"getCardDescription()\"></span>\n            <span translate=\"'ending'\"></span>\n            <span text=\"getMaskedCard()\"></span>\n        </label>\n    </div>\n    <div class=\"payment-method-content\">\n        <!-- ko foreach: getRegion('messages') -->\n        <!-- ko template: getTemplate() --><!-- /ko -->\n        <!--/ko-->\n        <div class=\"payment-method-billing-address\">\n            <span text=\"getCardHolderName()\"></span>\n            <br>\n            <span data-bind=\"html: getFormattedCardBillingAddress()\">></span>\n        </div>\n        <div class=\"checkout-agreements-block\">\n            <!-- ko foreach: $parent.getRegion('before-place-order') -->\n            <!-- ko template: getTemplate() --><!-- /ko -->\n            <!--/ko-->\n        </div>\n        <div class=\"actions-toolbar\">\n            <div class=\"primary\">\n                <button class=\"action primary checkout\"\n                        type=\"submit\"\n                        click=\"onPlaceOrder\">\n                    <span translate=\"'Place Order'\"></span>\n                </button>\n            </div>\n        </div>\n    </div>\n</div>\n"}
}});
